function processUser(userId, callback) {
  fetchUser(userId, function(err, user) {
    if (err) {
      callback(err);
    } else {
      fetchProfile(user.id, function(err, profile) {
        if (err) {
          callback(err);
        } else {
          fetchPosts(profile.id, function(err, posts) {
            if (err) {
              callback(err);
            } else {
              callback(null, { user, profile, posts });
            }
          });
        }
      });
    }
  });
}

